(function (w, d) {
  var s = d.currentScript
  if (!s) return
  var writeKey = (s.getAttribute('data-write-key') || '').trim()
  if (!writeKey) return
  var defaultBase = w.location.origin || ''
  try {
    if (s.src) {
      defaultBase = new URL(s.src, w.location.href).origin
    }
  } catch (_) {}
  var apiBase = (s.getAttribute('data-api-base') || defaultBase || '').replace(/\/+$/, '')
  var endpoint = apiBase + '/api/ingest/' + writeKey
  var endpointOrigin = ''
  try {
    endpointOrigin = new URL(endpoint, w.location.href).origin
  } catch (_) {}

  function getClientId() {
    var key = 'ym_monitor_cid'
    try {
      var old = w.localStorage.getItem(key)
      if (old) return old
      var id = 'cid_' + Math.random().toString(36).slice(2, 10)
      w.localStorage.setItem(key, id)
      return id
    } catch (_) {
      return 'cid_' + Math.random().toString(36).slice(2, 10)
    }
  }

  function send(payload) {
    var body = JSON.stringify(payload)
    var blob = new Blob([body], { type: 'application/json' })
    // sendBeacon 在跨域场景下会以 include 凭据模式发送，容易触发 CORS 拒绝。
    // 因此仅在同源时优先使用 sendBeacon，跨域统一走 fetch + credentials: omit。
    if (endpointOrigin && endpointOrigin === w.location.origin) {
      if (w.navigator.sendBeacon && w.navigator.sendBeacon(endpoint, blob)) return
    }
    w.fetch(endpoint, {
      method: 'POST',
      mode: 'cors',
      credentials: 'omit',
      headers: { 'Content-Type': 'application/json' },
      body: body,
      keepalive: true,
    }).catch(function () {})
  }

  function track(eventName, meta) {
    send({
      event_name: eventName || 'event',
      page: w.location.pathname,
      client_id: getClientId(),
      occurred_at: Date.now(),
      meta: meta || {},
    })
  }

  w.ymTrack = track
  track('page_view', { title: d.title, referrer: d.referrer || '' })
})(window, document)
